useEffect(() => {
  const cached = localStorage.getItem('carousel_covers');
  const { data, timestamp } = JSON.parse(cached || '{}');
  if (Date.now() - timestamp < 86400000) {
    setCovers(data);
    return;
  }
  fetchCarouselCovers().then(data => {
    setCovers(data);
    localStorage.setItem('carousel_covers', JSON.stringify({
      data, timestamp: Date.now()
    }));
  });
}, [])
